# BEST PRACTICE: Chunked Retrieval with Streaming + Monitoring
class CricketScoreRAG:
    def __init__(self, embedding_model, llm_stream):
        self.embedding_model = embedding_model
        self.llm_stream = llm_stream
        self.retrieval_cache = {}  # Cache hot documents

    def stream_match_commentary(self, cricket_query: str):
        # Pre-retrieve ALL context (one latency hit)
        query_embedding = self.embedding_model.encode(cricket_query)
        top_k_innings = self.retrieve_cached_innings(
            query_embedding, 
            k=5,
            cache_threshold=0.85  # Use cache if similarity > 0.85
        )

        # Assemble context window
        context = self._build_context_window(top_k_innings)

        # Stream generation with clear feedback mechanism
        token_count = 0
        for token in self.llm_stream.generate(cricket_query, context):
            yield token
            token_count += 1

            # Log streaming metrics
            if token_count % 10 == 0:
                self.metrics.record_streaming_latency(token_count)

    # ANTI-PATTERN: Retrieving during each generation step
    def stream_match_commentary_bad(self, cricket_query: str):
        for token in self.llm_stream.generate_token():
            # ❌ WRONG: Triggers 50+ retrievals for a 50-token response
            if self.should_retrieve_new_context(token):
                new_docs = self.retrieve_innings(cricket_query)  # EXPENSIVE
            yield token
            # Result: 3-5x latency increase, unstable token arrival times

# BEST PRACTICE: Cache warm innings data
class CachedInningsRetriever:
    def retrieve_cached_innings(self, embedding, k=5, cache_threshold=0.85):
        cache_hits = self.retrieval_cache.get(embedding.tobytes())
        if cache_hits and cache_hits['similarity'] > cache_threshold:
            return cache_hits['documents']  # <10ms response

        # Cache miss: retrieve, store, return
        docs = self.vector_store.search(embedding, k=k)
        self.retrieval_cache[embedding.tobytes()] = {
            'documents': docs,
            'similarity': docs[0]['score']
        }
        return docs
